import tiktoken

# For GPT-4 / GPT-4o family
enc = tiktoken.encoding_for_model("gpt-4o")

def token_ids_for(text: str) -> list[int]:
    """Return all token IDs that the string tokenizes to."""
    return enc.encode(text)

# Find every token ID that encodes a target word
def find_token_ids(words: list[str]) -> dict[str, list[int]]:
    result = {}
    for word in words:
        # Try common surface variants: bare, leading space, leading newline
        ids = set()
        for variant in [word, " " + word, "\n" + word, word.lower(), " " + word.lower()]:
            ids.update(enc.encode(variant))
        result[word] = sorted(ids)
    return result

banned_words = ["violence", "explicit", "nsfw"]
token_map = find_token_ids(banned_words)
print(token_map)
# {"violence": [36186, 29492, ...], "explicit": [...], ...}

def build_logit_bias(
    ban_words: list[str] | None = None,
    boost_words: list[str] | None = None,
    ban_value: float = -100,
    boost_value: float = 5,
    enc: tiktoken.Encoding = None,
) -> dict[str, float]:
    """Build a logit_bias dict ready for the OpenAI API."""
    if enc is None:
        enc = tiktoken.encoding_for_model("gpt-4o")
    bias: dict[str, float] = {}
    for word in (ban_words or []):
        for variant in [word, " " + word, word.lower(), " " + word.lower()]:
            for tid in enc.encode(variant):
                bias[str(tid)] = ban_value
    for word in (boost_words or []):
        for variant in [word, " " + word]:
            for tid in enc.encode(variant):
                bias[str(tid)] = boost_value
    return bias

import tiktoken
from openai import OpenAI

client = OpenAI()
enc = tiktoken.encoding_for_model("gpt-4o")

# Clinical terms to boost (preference, not force)
clinical_boosts = [
    "hypertension", "myocardial", "contraindicated",
    "administration", "etiology", "prognosis"
]

# Colloquial terms to slightly suppress
colloquial_bans = ["heart attack", "high blood pressure", "bad"]

def partial_bias(words, value, enc):
    bias = {}
    for w in words:
        for v in [w, " " + w, w.lower(), " " + w.lower()]:
            try:
                for tid in enc.encode(v):
                    bias[str(tid)] = value
            except Exception:
                pass
    return bias

logit_bias = {}
logit_bias.update(partial_bias(clinical_boosts, 3, enc))
logit_bias.update(partial_bias(colloquial_bans, -5, enc))

response = client.chat.completions.create(
    model="gpt-4o",
    messages=[
        {"role": "system", "content": "You are a clinical documentation assistant."},
        {"role": "user", "content": "Summarise: Patient has high blood pressure and had a heart attack last year."},
    ],
    logit_bias=logit_bias,
    max_tokens=150,
)
print(response.choices[0].message.content)
# Output uses "hypertension" and "myocardial infarction" naturally

import json, boto3, tiktoken
from functools import lru_cache
from openai import OpenAI

client = OpenAI()
dynamodb = boto3.resource("dynamodb", region_name="us-east-1")
table = dynamodb.Table("LogitBiasConfig")

@lru_cache(maxsize=1)
def get_logit_bias(model: str = "gpt-4o") -> dict[str, float]:
    """Load pre-computed bias dict from DynamoDB cache."""
    item = table.get_item(Key={"model": model})["Item"]
    return json.loads(item["bias_json"])

def safe_generate(user_prompt: str, system_prompt: str) -> str:
    bias = get_logit_bias()
    resp = client.chat.completions.create(
        model="gpt-4o",
        messages=[
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": user_prompt},
        ],
        logit_bias=bias,
        max_tokens=512,
        temperature=0.7,
    )
    return resp.choices[0].message.content

# Rebuild script (run weekly via Lambda)
def rebuild_bias_table(excluded_brands: list[str], model: str = "gpt-4o"):
    enc = tiktoken.encoding_for_model(model)
    bias: dict[str, float] = {}
    for brand in excluded_brands:
        for variant in [brand, " " + brand, brand.lower(), " " + brand.lower(),
                        brand.upper(), " " + brand.upper()]:
            for tid in enc.encode(variant):
                bias[str(tid)] = -100
    table.put_item(Item={"model": model, "bias_json": json.dumps(bias)})
    print(f"Stored {len(bias)} token ID entries for {len(excluded_brands)} brands")
